#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int count = 0;
        for (int i = 0; i < 10; i++) {
            for (int j = 0; j < 10; j++) {
                int time;
                scanf("%d", &time);
                if (time <= 30) count++;
            }
        }
        if (count >= 60) printf("yes\n");
        else printf("no\n");
    }
    return 0;
}

